SELECT hd.id, hd.satellite_id, hd.sensor_id, hd.date, hd.time, hd.resolution, hd.type, hd.bands, hd.cloud, hd.topleftlatitude, hd.topleftlongitude, hd.toprightlatitude, hd.toprightlongitude, hd.bottomleftlatitude, hd.bottomleftlongitude, hd.bottomrightlatitude, hd.bottomrightlongitude, hd.centerlongitude, hd.centerlatitude, hd.LEVEL, hd.pngtopleftlatitude, hd.pngtopleftlongitude, hd.pngtoprightlatitude, hd.pngtoprightlongitude, hd.pngbottomleftlatitude, hd.pngbottomleftlongitude, hd.pngbottomrightlatitude, hd.product_id, hd.pngbottomrightlongitude, hd.data_type, hd.the_geom as the_geom, hfi.id AS png_id, hfi.thumbnail_file_url AS png_url, hfi.thumb_chart_file_url AS small_png_url FROM htht_dms_sate_data_info hd LEFT JOIN htht_dms_sate_data_file_info hfi ON ( hd.id = hfi.data_id) WHERE 1 = 1
and hd.resolution=#{resolution}
and hd.date >= #{beginTime} and hd.date<=#{endTime}
and hd.cloud<=#{cloud} and
(hd.satellite_id=#{item.satelliteId})
(hd.satellite_id=#{item.satelliteId} and hd.sensor_id like CONCAT(#{item.sensorId},'%'))
and hd.data_type in
#{item}
order by date desc,time desc
order by
date ${item.sortord},time ${item.sortord}
${item.sort} ${item.sortord}

select l.*,hfi.id AS png_id, hfi1.id AS small_png_id,hfi.file_url AS png_url, hfi1.file_url AS small_png_url from (SELECT hd.id, hd.satellite_id, hd.sensor_id, hd.date, hd.time, hd.NAME, hd.resolution, hd.type, hd.bands, hd.cloud, hd.topleftlatitude, hd.topleftlongitude, hd.toprightlatitude, hd.toprightlongitude, hd.bottomleftlatitude, hd.bottomleftlongitude, hd.bottomrightlatitude, hd.bottomrightlongitude, hd.centerlongitude, hd.centerlatitude, hd.LEVEL, hd.pngtopleftlatitude, hd.pngtopleftlongitude, hd.pngtoprightlatitude, hd.pngtoprightlongitude, hd.pngbottomleftlatitude, hd.pngbottomleftlongitude, hd.pngbottomrightlatitude, hd.pngbottomrightlongitude FROM htht_dms_sate_data_info hd INNER JOIN htht_dms_sate_data_meta hc ON hd.id = hc.data_id WHERE 1 = 1
and hd.resolution=#{resolution}
and hd.date >= #{beginTime} and hd.date<=#{endTime}
and hd.cloud<=#{cloud} and hd.data_type=#{dataType} and
(hd.satellite_id=#{item.satelliteId})
(hd.satellite_id=#{item.satelliteId} and hd.sensor_id like CONCAT(#{item.sensorId},'%'))
and ST_Intersects(hc.the_geom,ST_GeometryFromText(#{geostr}))
order by date desc,time desc
order by
date ${item.sortord},time ${item.sortord}
${item.sortord} ${item.sortord}
limit #{start},#{end} ) l LEFT JOIN htht_dms_sate_data_file_info hfi ON ( l.id = hfi.data_id ) LEFT JOIN htht_dms_sate_data_file_info hfi1 ON ( l.id = hfi1.data_id
)

SELECT count(*)
FROM
htht_dms_sate_data_info hi INNER JOIN htht_dms_sate_data_meta hm on hm.data_id=hi.id where 1=1

    and hi.resolution=#{resolution}


    and hi.date>=#{beginTime} and hi.date<=#{endTime}

and hi.cloud<=#{cloud}
and hi.data_type=#{dataType}
and


        (hi.satellite_id=#{item.satelliteId})


        (hi.satellite_id=#{item.satelliteId} and hi.sensor_id like CONCAT(#{item.sensorId},'%'))



    and ST_Intersects(hm.the_geom,ST_GeometryFromText(#{geostr}))

SELECT ST_AsText(ST_Intersection(the_geom,ST_GeometryFromText(#{geostr}))) as intersectgeostr FROM
htht_dms_sate_data_info hi
INNER JOIN htht_dms_sate_data_meta hm on hm.data_id=hi.id
where 1=1

    and hi.resolution=#{resolution}


    and hi.date >=#{beginTime} and hi.date<=#{endTime}

and hi.cloud<=#{cloud}

    and hi.data_type=#{dataType}

and


        (hi.satellite_id=#{item.satelliteId})


        (hi.satellite_id=#{item.satelliteId} and hi.sensor_id like CONCAT(#{item.sensorId},'%'))



    and ST_Intersects(hm.the_geom,ST_GeometryFromText(#{geostr}))

SELECT cast(sum(area) as signed) sumarea,count(*) as count FROM
htht_dms_sate_data_info hi
INNER JOIN htht_dms_sate_data_meta hm on hm.data_id=hi.id
where 1=1

    and hi.resolution=#{resolution}


    and hi.date>=#{beginTime} and hi.date<=#{endTime}

and hi.cloud<=#{cloud}

    and hi.data_type=#{dataType}

and


        (hi.satellite_id=#{item.satelliteId})


        (hi.satellite_id=#{item.satelliteId} and hi.sensor_id like CONCAT(#{item.sensorId},'%'))



    and ST_Intersects(hm.the_geom,ST_GeometryFromText(#{geostr}))

select the_gemo
from htht_region_geo_info
where regionid = #{regionId}

SELECT hi.the_geom as geostr
FROM
htht_dms_sate_data_info hi
where 1=1

    and hi.resolution=#{resolution}


    and hi.date>=#{beginTime} and hi.date<=#{endTime}

and hi.cloud<=#{cloud}

    and hi.data_type=#{dataType}

and


        (hi.satellite_id=#{item.satelliteId})


        (hi.satellite_id=#{item.satelliteId} and hi.sensor_id like CONCAT(#{item.sensorId},'%'))

SELECT hi.the_geom as geostr,hi.area,hi.data_type
FROM
htht_dms_sate_data_info hi
where 1=1

    and hi.resolution=#{resolution}


    and hi.date>=#{beginTime} and hi.date<=#{endTime}

and hi.cloud<=#{cloud}
and


        (hi.satellite_id=#{item.satelliteId})


        (hi.satellite_id=#{item.satelliteId} and hi.sensor_id like CONCAT(#{item.sensorId},'%'))

select l.centerlatitude, l.centerlongitude, l.topleftlatitude, l.topleftlongitude, l.toprightlatitude, l.bottomrightlongitude, l.bottomrightlatitude, l.bottomleftlongitude, l.bottomleftlatitude, l.toprightlongitude,hfi.id as pngId from (SELECT hi.id,hi.centerlatitude, hi.centerlongitude, hi.topleftlatitude, hi.topleftlongitude, hi.toprightlatitude, hi.bottomrightlongitude, hi.bottomrightlatitude, hi.bottomleftlongitude, hi.bottomleftlatitude, hi.toprightlongitude FROM htht_dms_sate_data_info hi INNER JOIN htht_dms_sate_data_meta hm on hm.data_id=hi.id where 1=1
and hi.resolution=#{resolution}
