and hi.cloud<=#{cloud}
and hi.data_type=#{dataType}
and
(hi.satellite_id=#{item.satelliteId})
(hi.satellite_id=#{item.satelliteId} and hi.sensor_id like CONCAT(#{item.sensorId},'%'))
