SELECT d.id as d_id, d.region, d.file_name as d_file_name, d.space_resolution, d.time_resolution, d.data_type, d.file_type as d_file_type, d.mark, d.issue, d.cycle, f.id as f_id, f.file_type as f_file_type, f.file_url, f.file_name as f_file_name FROM `htht_satellite_thematic_data_info` as d ,htht_satellite_thematic_data_file_info as f where d.tree_id in
#{item}
and d.issue BETWEEN #{beginTimeStr} and #{endTimeStr} and d.id=f.data_id and f.file_type in ('jpg','png') and f.version='0' order by issue desc
